def load_csv_data(file_path: Path, expected_header: List[str] = None) -> List[Dict[str, str]]:
    """Load CSV data with validation."""
    if not file_path.exists():
        return []

    data = []
    with open(file_path, 'r', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        if expected_header and reader.fieldnames != expected_header:
            # Try to handle potential header mismatches
            f.seek(0)
            lines = f.readlines()
            if len(lines) > 0:
                actual_header = lines[0].strip().split(',')
                if len(actual_header) == len(expected_header):
                    reader = csv.DictReader(lines, fieldnames=expected_header)

        for row in reader:
            # Clean up values
            cleaned_row = {}
            for key, value in row.items():
                if value is None:
                    cleaned_row[key] = ""
                else:
                    cleaned_row[key] = str(value).strip()
            data.append(cleaned_row)

    return data

def load_json_data(file_path: Path) -> List[Dict[str, Any]]:
    """Load JSON data."""
    if not file_path.exists():
        return []

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if isinstance(data, list):
                return data
            elif isinstance(data, dict):
                return [data]
            else:
                return []
    except (json.JSONDecodeError, UnicodeDecodeError):
        return []

def search_in_text(text: str, query: str) -> bool:
    """Case-insensitive search in text."""
    if not text:
        return False
    return query.lower() in text.lower()

