def search_debugging_techniques(query: str, max_results: int = 5) -> List[Dict[str, Any]]:
    """Search CSV files for debugging techniques, symptoms, and fixes."""
    results = []

    # Load all CSV data
    all_data = []

    # Load go memory leak data
    go_memory_data = load_csv_data(
        CSV_PATHS["go_memory_leak"],
        ["symptom", "possible_cause", "quick_fix"]
    )
    for row in go_memory_data:
        row["source"] = "go_memory_leak"
        row["data_type"] = "csv"
        all_data.append(row)

    # Load debugging strategies data
    strategies_data = load_csv_data(
        CSV_PATHS["debugging_strategies"],
        ["published_time", "title", "tracking_image_count", "sample_tracking_url", "parameters_present"]
    )
    for row in strategies_data:
        row["source"] = "debugging_strategies"
        row["data_type"] = "csv"
        all_data.append(row)

    # Load backend guide data
    backend_data = load_csv_data(
        CSV_PATHS["backend_guide"],
        ["error_code", "security_message", "platform", "favicon_url"]
    )
    for row in backend_data:
        row["source"] = "backend_guide"
        row["data_type"] = "csv"
        all_data.append(row)

    # Load codebases guide data
    codebases_data = load_csv_data(
        CSV_PATHS["codebases_guide"],
        ["error_code", "security_message", "platform", "favicon_url"]
    )
    for row in codebases_data:
        row["source"] = "codebases_guide"
        row["data_type"] = "csv"
        all_data.append(row)

    # Load code flows data if exists
    if CSV_PATHS["code_flows"].exists():
        code_flows_data = load_csv_data(CSV_PATHS["code_flows"], None)
        for row in code_flows_data:
            row["source"] = "code_flows"
